type RuntimeEnvironmentWithOther = "development" | "test" | "production" | "other";

export type RuntimeEnvironment = "development" | "test" | "production";

const TRUE_VALUES = new Set(["1", "true", "yes", "on"]);
const FALSE_VALUES = new Set(["0", "false", "no", "off"]);

type RuntimeEnvironmentSource = Record<string, string | undefined>;

function readOptionalString(name: string, env: RuntimeEnvironmentSource): string | null {
  const value = env[name];
  if (typeof value !== "string") {
    return null;
  }
  const normalized = value.trim();
  return normalized ? normalized : null;
}

export function readBooleanEnvFlag(
  name: string,
  fallback: boolean,
  env: RuntimeEnvironmentSource = process.env,
): boolean {
  const raw = String(readOptionalString(name, env) ?? "").trim().toLowerCase();
  if (!raw) return fallback;
  if (TRUE_VALUES.has(raw)) return true;
  if (FALSE_VALUES.has(raw)) return false;
  return fallback;
}

export function normalizeRuntimeEnvironment(rawValue: unknown): RuntimeEnvironmentWithOther {
  const raw = String(rawValue || "development").trim().toLowerCase();
  if (raw === "development" || raw === "test" || raw === "production") {
    return raw;
  }
  return "other";
}

export function resolveRuntimeEnvironment(rawValue: unknown): RuntimeEnvironment {
  const normalized = normalizeRuntimeEnvironment(rawValue);
  if (normalized === "production" || normalized === "test") {
    return normalized;
  }
  return "development";
}

export function isLoopbackHostname(value: string): boolean {
  const normalized = String(value || "").trim().toLowerCase();
  return normalized === "127.0.0.1" || normalized === "localhost" || normalized === "::1";
}

function resolvePublicAppHost(env: RuntimeEnvironmentSource): string | null {
  const publicBaseUrl =
    readOptionalString("PUBLIC_APP_URL", env)
    || readOptionalString("APP_BASE_URL", env)
    || readOptionalString("CLIENT_APP_URL", env);
  if (!publicBaseUrl) {
    return null;
  }

  try {
    return new URL(publicBaseUrl).hostname || null;
  } catch {
    return null;
  }
}

export function isStrictLocalDevelopmentEnvironment(
  env: RuntimeEnvironmentSource = process.env,
): boolean {
  if (normalizeRuntimeEnvironment(env.NODE_ENV) !== "development") {
    return false;
  }

  const host = readOptionalString("HOST", env);
  if (host && !isLoopbackHostname(host)) {
    return false;
  }

  const publicAppHost = resolvePublicAppHost(env);
  if (!publicAppHost) {
    return true;
  }
  return isLoopbackHostname(publicAppHost);
}

export function isProductionLikeEnvironment(
  env: RuntimeEnvironmentSource = process.env,
): boolean {
  const nodeEnv = normalizeRuntimeEnvironment(env.NODE_ENV);
  if (nodeEnv === "test") {
    return false;
  }
  if (nodeEnv === "production" || nodeEnv === "other") {
    return true;
  }
  return !isStrictLocalDevelopmentEnvironment(env);
}

import { z } from "zod";
import { ERROR_CODES } from "../../shared/error-codes";
import { badRequest } from "./errors";

export function ensureObject(value: unknown): Record<string, unknown> | null {
  if (value && typeof value === "object" && !Array.isArray(value)) {
    return value as Record<string, unknown>;
  }
  return null;
}

export type RequestValidationIssue = {
  code: string;
  message: string;
  path: string;
};

function buildRequestValidationIssues(error: z.ZodError): RequestValidationIssue[] {
  return error.issues.map((issue) => ({
    code: issue.code,
    message: issue.message,
    path: issue.path.length > 0 ? issue.path.map(String).join(".") : "body",
  }));
}

export function parseRequestBody<TSchema extends z.ZodTypeAny>(
  schema: TSchema,
  value: unknown,
): z.infer<TSchema> {
  const parsed = schema.safeParse(value);
  if (parsed.success) {
    return parsed.data;
  }

  const details = buildRequestValidationIssues(parsed.error);
  throw badRequest(
    details[0]?.message || "Request body is invalid.",
    ERROR_CODES.REQUEST_BODY_INVALID,
    details,
  );
}

export const DEFAULT_READ_STRING_MAX_LENGTH = 2_048;

export function readNonEmptyString(
  value: unknown,
  maxLength = DEFAULT_READ_STRING_MAX_LENGTH,
): string {
  const normalized = String(value ?? "").trim();
  if (normalized.length > maxLength) {
    throw badRequest(
      `String value exceeds maximum length of ${maxLength} characters.`,
      ERROR_CODES.REQUEST_BODY_INVALID,
    );
  }
  return normalized;
}

export function readOptionalString(
  value: unknown,
  maxLength = DEFAULT_READ_STRING_MAX_LENGTH,
): string | undefined {
  const normalized = readNonEmptyString(value, maxLength);
  return normalized || undefined;
}

export function readInteger(value: unknown, fallback: number): number {
  const parsed = Number(value);
  if (!Number.isFinite(parsed)) return fallback;
  return Math.trunc(parsed);
}

export function clampInteger(value: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, Math.trunc(value)));
}

export function readBooleanFlag(value: unknown): boolean {
  if (typeof value === "boolean") return value;
  const normalized = readNonEmptyString(value).toLowerCase();
  return normalized === "1" || normalized === "true" || normalized === "yes";
}

export function readStringList(value: unknown): string[] {
  if (Array.isArray(value)) {
    return value
      .map((item) => readNonEmptyString(item))
      .filter(Boolean);
  }

  const normalized = readNonEmptyString(value);
  if (!normalized) return [];

  return normalized
    .split(",")
    .map((part) => readNonEmptyString(part))
    .filter(Boolean);
}

export function readDate(value: unknown): Date | undefined {
  const normalized = readNonEmptyString(value);
  if (!normalized) return undefined;

  const parsed = new Date(normalized);
  if (Number.isNaN(parsed.getTime())) {
    return undefined;
  }

  return parsed;
}

import type { NextFunction, Request, Response } from "express";
import { HttpError } from "../http/errors";
import { logger } from "../lib/logger";

type ErrorLike = {
  message?: string;
  code?: string;
  type?: string;
  status?: number;
  statusCode?: number;
};

type ApiErrorResponse = {
  ok: false;
  message: string;
  error?: {
    code?: string;
    message: string;
    details?: unknown;
  };
};

function buildApiErrorResponse(
  message: string,
  options?: { code?: string | undefined; details?: unknown; includeError?: boolean | undefined },
): ApiErrorResponse {
  const includeError = options?.includeError || Boolean(options?.code || options?.details !== undefined);

  return {
    ok: false,
    message,
    ...(includeError
      ? {
          error: {
            ...(options?.code ? { code: options.code } : {}),
            message,
            ...(options?.details !== undefined ? { details: options.details } : {}),
          },
        }
      : {}),
  };
}

export function errorHandler(err: unknown, req: Request, res: Response, next: NextFunction) {
  if (res.headersSent) {
    return next(err);
  }

  const error = err as ErrorLike;

  if (error?.type === "entity.too.large" || error?.status === 413 || error?.statusCode === 413) {
    return res.status(413).json(buildApiErrorResponse("The request payload is too large to process.", {
      code: "PAYLOAD_TOO_LARGE",
      includeError: true,
    }));
  }

  if (err instanceof HttpError) {
    if (!err.expose) {
      logger.error("Unhandled API HttpError", {
        path: req.path,
        method: req.method,
        code: err.code,
        statusCode: err.statusCode,
        message: err.message,
      });

      return res.status(err.statusCode).json(buildApiErrorResponse("Internal server error"));
    }

    return res.status(err.statusCode).json(buildApiErrorResponse(err.message, {
      ...(err.code ? { code: err.code } : {}),
      ...(err.details !== undefined ? { details: err.details } : {}),
    }));
  }

  logger.error("Unhandled API error", {
    path: req.path,
    method: req.method,
    code: error?.code,
    message: error?.message,
  });

  return res.status(500).json(buildApiErrorResponse("Internal server error"));
}

