import os from "node:os";
import path from "node:path";
import { randomUUID } from "node:crypto";
import { mkdtemp, rm } from "node:fs/promises";
import { pipeline } from "node:stream/promises";
import {
  parseImportUploadFile,
  stripImportUploadExtension,
} from "../services/import-upload-parser";

export type MultipartImportBody = {
  name?: string;
  filename?: string;
  data?: Record<string, string>[];
};

export const IMPORT_TOO_LARGE_MESSAGE = "The selected file is too large to import. Please split it into smaller files and try again.";

export function normalizeImportName(rawValue: string | undefined, fallbackFilename: string) {
  const normalized = String(rawValue || "").trim();
  if (normalized) {
    return normalized.slice(0, 160);
  }

  return stripImportUploadExtension(fallbackFilename).slice(0, 160);
}

export function resolveImportMultipartFailure(error: unknown, fallbackMessage = "Failed to parse import upload.") {
  const message =
    error instanceof Error && error.message
      ? error.message
      : fallbackMessage;

  const statusCode = /too large|size limit/i.test(message) ? 413 : 400;
  return {
    message: statusCode === 413 ? IMPORT_TOO_LARGE_MESSAGE : message,
    statusCode,
  };
}

export async function parseMultipartImportUpload(params: {
  file: NodeJS.ReadableStream;
  filename: string;
}) {
  const { file, filename } = params;
  const tempDir = await mkdtemp(path.join(os.tmpdir(), "sqr-import-upload-"));
  const tempFilePath = path.join(tempDir, `${Date.now()}-${randomUUID()}.upload`);
  let exceededSizeLimit = false;

  file.once("limit", () => {
    exceededSizeLimit = true;
  });

  try {
    await pipeline(
      file,
      fs.createWriteStream(tempFilePath, { flags: "wx" }),
    );

    if (exceededSizeLimit) {
      throw new Error(IMPORT_TOO_LARGE_MESSAGE);
    }

    const parsed = await parseImportUploadFile(filename, tempFilePath);
    if (parsed.error) {
      throw new Error(parsed.error);
    }

    return {
      dataRows: parsed.rows,
      filename,
    };
  } finally {
    await rm(tempFilePath, { force: true }).catch(() => undefined);
    await rm(tempDir, { recursive: true, force: true }).catch(() => undefined);
  }
}

import { parseCsvBuffer, parseCsvFile } from "./import-upload-csv-utils";
import { parseExcelBuffer, parseExcelFile } from "./import-upload-excel-utils";
import {
  isSupportedSpreadsheet,
  stripImportUploadExtension,
} from "./import-upload-file-utils";
import type { ParsedImportUploadResult } from "./import-upload-types";
export type { ImportRow, ParsedImportUploadResult } from "./import-upload-types";

export { stripImportUploadExtension };

export function parseImportUploadBuffer(filename: string, buffer: Buffer): ParsedImportUploadResult {
  const normalizedFilename = String(filename || "").trim().toLowerCase();
  if (!isSupportedSpreadsheet(normalizedFilename)) {
    return { headers: [], rows: [], error: "Please select a CSV or Excel file (.xlsx, .xls, .xlsb)" };
  }

  if (normalizedFilename.endsWith(".csv")) {
    return parseCsvBuffer(buffer);
  }

  return parseExcelBuffer(buffer);
}

export async function parseImportUploadFile(filename: string, filePath: string): Promise<ParsedImportUploadResult> {
  const normalizedFilename = String(filename || "").trim().toLowerCase();
  if (!isSupportedSpreadsheet(normalizedFilename)) {
    return { headers: [], rows: [], error: "Please select a CSV or Excel file (.xlsx, .xls, .xlsb)" };
  }

  if (normalizedFilename.endsWith(".csv")) {
    return parseCsvFile(filePath);
  }

  return await parseExcelFile(filePath);
}

import fs from "node:fs";
import readline from "node:readline";
import {
  createUploadFileAccessError,
  isFileAccessError,
} from "./import-upload-file-utils";
import type { ImportRow, ParsedImportUploadResult } from "./import-upload-types";

function parseCsvLine(line: string): string[] {
  const result: string[] = [];
  let current = "";
  let inQuotes = false;

  for (let index = 0; index < line.length; index += 1) {
    const char = line[index];
    if (char === '"') {
      if (inQuotes && line[index + 1] === '"') {
        current += '"';
        index += 1;
      } else {
        inQuotes = !inQuotes;
      }
    } else if (char === "," && !inQuotes) {
      result.push(current.trim());
      current = "";
    } else {
      current += char;
    }
  }

  result.push(current.trim());
  return result;
}

function findHeaderLine(lines: string[]) {
  let headerLineIndex = 0;
  while (headerLineIndex < lines.length && !lines[headerLineIndex].trim()) {
    headerLineIndex += 1;
  }
  return headerLineIndex;
}

function toParsedCsvRow(headers: string[], values: string[]): ImportRow {
  const row: ImportRow = {};
  headers.forEach((header, headerIndex) => {
    row[header] = values[headerIndex] || "";
  });
  return row;
}

export function parseCsvBuffer(buffer: Buffer): ParsedImportUploadResult {
  const text = buffer.toString("utf8").replace(/^\ufeff/, "");
  const lines = text.split(/\r?\n/);

  if (lines.length === 0) {
    return { headers: [], rows: [], error: "CSV file is empty." };
  }

  const headerLineIndex = findHeaderLine(lines);
  if (headerLineIndex >= lines.length) {
    return { headers: [], rows: [], error: "CSV file is empty." };
  }

  const headers = parseCsvLine(lines[headerLineIndex]);
  const rows: ImportRow[] = [];

  for (let index = headerLineIndex + 1; index < lines.length; index += 1) {
    const line = lines[index];
    if (!line.trim()) continue;

    const row = toParsedCsvRow(headers, parseCsvLine(line));
    if (Object.values(row).some((value) => value !== "")) {
      rows.push(row);
    }
  }

  return { headers, rows };
}

export async function parseCsvFile(filePath: string): Promise<ParsedImportUploadResult> {
  const stream = fs.createReadStream(filePath, { encoding: "utf8" });
  const lineReader = readline.createInterface({
    input: stream,
    crlfDelay: Infinity,
  });
  let inputStreamError: unknown = null;
  const handleInputStreamError = (error: Error) => {
    inputStreamError = error;
    lineReader.close();
  };
  stream.once("error", handleInputStreamError);

  const rows: ImportRow[] = [];
  let headers: string[] = [];
  let headerResolved = false;

  try {
    for await (const rawLine of lineReader) {
      const line = String(rawLine ?? "");
      const normalizedLine = headerResolved ? line : line.replace(/^\ufeff/, "");
      if (!normalizedLine.trim()) {
        continue;
      }

      if (!headerResolved) {
        headers = parseCsvLine(normalizedLine);
        headerResolved = true;
        continue;
      }

      const row = toParsedCsvRow(headers, parseCsvLine(normalizedLine));
      if (Object.values(row).some((value) => value !== "")) {
        rows.push(row);
      }
    }

    if (inputStreamError) {
      throw inputStreamError;
    }
  } catch (error) {
    if (isFileAccessError(error)) {
      return createUploadFileAccessError();
    }
    throw error;
  } finally {
    stream.off("error", handleInputStreamError);
    lineReader.close();
    stream.destroy();
  }

  if (!headerResolved || headers.length === 0) {
    return { headers: [], rows: [], error: "CSV file is empty." };
  }

  return { headers, rows };
}

import type { ParsedImportUploadResult } from "./import-upload-types";

const SUPPORTED_IMPORT_UPLOAD_EXTENSION_PATTERN = /\.(csv|xlsx|xls|xlsb)$/i;

export function isFileAccessError(error: unknown) {
  const code =
    typeof error === "object" && error && "code" in error
      ? String((error as { code?: unknown }).code || "")
      : "";
  return ["ENOENT", "EACCES", "EPERM", "EBUSY"].includes(code);
}

export function createUploadFileAccessError(): ParsedImportUploadResult {
  return {
    headers: [],
    rows: [],
    error: "Cannot access the uploaded file. Please try again.",
  };
}

export function isSupportedSpreadsheet(filename: string) {
  return SUPPORTED_IMPORT_UPLOAD_EXTENSION_PATTERN.test(filename);
}

export function stripImportUploadExtension(filename: string) {
  return filename.replace(SUPPORTED_IMPORT_UPLOAD_EXTENSION_PATTERN, "");
}

import fs from "node:fs";
import * as xlsx from "xlsx";
import {
  createUploadFileAccessError,
  isFileAccessError,
} from "./import-upload-file-utils";
import type { ImportRow, ParsedImportUploadResult } from "./import-upload-types";

function mapExcelReadError(error: unknown): ParsedImportUploadResult {
  const message = error instanceof Error ? error.message : "Failed to read Excel file";
  if (message.includes("password") || message.includes("encrypt")) {
    return { headers: [], rows: [], error: "File is password protected" };
  }
  if (message.includes("Unsupported") || message.includes("corrupt")) {
    return { headers: [], rows: [], error: "File is corrupted or unsupported format" };
  }
  return { headers: [], rows: [], error: message };
}

function parseWorkbookJsonData(jsonData: unknown[][]): ParsedImportUploadResult {
  if (jsonData.length === 0) {
    return { headers: [], rows: [], error: "Excel file is empty." };
  }

  let headerRowIndex = 0;
  let maxNonEmptyCols = 0;

  for (let index = 0; index < Math.min(5, jsonData.length); index += 1) {
    const row = jsonData[index];
    const nonEmptyCount = row.filter((cell) => cell !== "" && cell !== null && cell !== undefined).length;
    if (nonEmptyCount > maxNonEmptyCols) {
      maxNonEmptyCols = nonEmptyCount;
      headerRowIndex = index;
    }
  }

  const headers = jsonData[headerRowIndex].map((header, index) => {
    const value = String(header || "").trim();
    return value || `Column_${index + 1}`;
  });

  const rows: ImportRow[] = [];

  for (let rowIndex = headerRowIndex + 1; rowIndex < jsonData.length; rowIndex += 1) {
    const rowData = jsonData[rowIndex];
    const hasAnyData = rowData.some((cell, index) => {
      if (index >= headers.length) return false;
      return String(cell ?? "").trim() !== "";
    });

    if (!hasAnyData) continue;

    const row: ImportRow = {};
    headers.forEach((header, index) => {
      const cellValue = rowData[index];
      row[header] =
        cellValue instanceof Date
          ? cellValue.toLocaleDateString("en-MY")
          : String(cellValue ?? "").trim();
    });
    rows.push(row);
  }

  return { headers, rows };
}

export function parseExcelBuffer(buffer: Buffer): ParsedImportUploadResult {
  let workbook;
  try {
    workbook = xlsx.read(buffer, {
      type: "buffer",
      cellDates: true,
      cellNF: false,
      cellText: false,
    });
  } catch (error: unknown) {
    return mapExcelReadError(error);
  }

  const firstSheetName = workbook.SheetNames[0];
  if (!firstSheetName) {
    return { headers: [], rows: [], error: "Excel file does not have any sheets." };
  }

  const worksheet = workbook.Sheets[firstSheetName];
  const jsonData = xlsx.utils.sheet_to_json(worksheet, {
    header: 1,
    defval: "",
    raw: false,
  }) as unknown[][];

  (workbook as { SheetNames?: unknown; Sheets?: unknown }).SheetNames = null;
  (workbook as { SheetNames?: unknown; Sheets?: unknown }).Sheets = null;
  workbook = null as never;

  return parseWorkbookJsonData(jsonData);
}

export async function parseExcelFile(filePath: string): Promise<ParsedImportUploadResult> {
  let buffer: Buffer;
  try {
    buffer = await fs.promises.readFile(filePath);
  } catch (error) {
    if (isFileAccessError(error)) {
      return createUploadFileAccessError();
    }
    const message = error instanceof Error ? error.message : "Failed to read Excel file";
    return { headers: [], rows: [], error: message };
  }

  return parseExcelBuffer(buffer);
}

import { asyncHandler } from "../http/async-handler";
import type { ImportsRouteContext } from "./imports-route-context";

export function registerImportsMutationRoutes(context: ImportsRouteContext) {
  const {
    app,
    importsController,
    authenticateToken,
    requireRole,
    importsMultipartRoute,
  } = context;

  app.post(
    "/api/imports",
    authenticateToken,
    importsMultipartRoute,
    asyncHandler(importsController.createImport),
  );

  app.patch("/api/imports/:id", authenticateToken, asyncHandler(importsController.renameImport));
  app.patch("/api/imports/:id/rename", authenticateToken, asyncHandler(importsController.renameImport));

  app.delete(
    "/api/imports/:id",
    authenticateToken,
    requireRole("admin", "superuser"),
    asyncHandler(importsController.deleteImport),
  );
}

import { asyncHandler } from "../http/async-handler";
import type { ImportsRouteContext } from "./imports-route-context";

export function registerImportsReadRoutes(context: ImportsRouteContext) {
  const {
    app,
    importsController,
    authenticateToken,
    searchRateLimiter,
  } = context;

  app.get("/api/data-rows", authenticateToken, asyncHandler(importsController.listDataRows));
  app.get("/api/imports", authenticateToken, asyncHandler(importsController.listImports));
  app.get("/api/imports/:id", authenticateToken, asyncHandler(importsController.getImport));
  app.get(
    "/api/imports/:id/data",
    authenticateToken,
    searchRateLimiter,
    asyncHandler(importsController.getImportDataPage),
  );
}

import { once } from "node:events";
import type { Server } from "node:http";
import { AddressInfo } from "node:net";
import express, { type Express, type RequestHandler } from "express";
import type { AuthenticatedRequest, AuthenticatedUser } from "../../auth/guards";

export function createJsonTestApp(): Express {
  const app = express();
  app.use(express.json());
  return app;
}

export async function startTestServer(app: Express) {
  const server = app.listen(0);
  await once(server, "listening");
  const address = server.address() as AddressInfo | null;
  if (!address) {
    throw new Error("Test server failed to start.");
  }

  return {
    server,
    baseUrl: `http://127.0.0.1:${address.port}`,
  };
}

export async function stopTestServer(server: Server) {
  await new Promise<void>((resolve, reject) => {
    server.close((error) => {
      if (error) {
        reject(error);
        return;
      }
      resolve();
    });
  });
}

export function createTestAuthenticateToken(
  defaults?: Partial<AuthenticatedUser>,
): RequestHandler {
  return (req: AuthenticatedRequest, res, next) => {
    const username = String(req.headers["x-test-username"] || defaults?.username || "").trim();
    const role = String(req.headers["x-test-role"] || defaults?.role || "").trim();

    if (!username || !role) {
      res.status(401).json({ message: "Token required" });
      return;
    }

    req.user = {
      userId: String(req.headers["x-test-userid"] || defaults?.userId || "").trim() || undefined,
      username,
      role,
      activityId: String(req.headers["x-test-activityid"] || defaults?.activityId || "test-activity"),
      status: defaults?.status,
      mustChangePassword: defaults?.mustChangePassword,
      passwordResetBySuperuser: defaults?.passwordResetBySuperuser,
      isBanned: defaults?.isBanned ?? null,
    };
    next();
  };
}

export function createTestRequireRole(): (...roles: string[]) => RequestHandler {
  return (...roles: string[]) => (req: AuthenticatedRequest, res, next) => {
    if (!req.user) {
      res.status(401).json({ message: "Authentication required." });
      return;
    }

    if (!roles.includes(req.user.role)) {
      res.status(403).json({ message: "Forbidden" });
      return;
    }

    next();
  };
}

export function createTestRequireTabAccess(): (tabId: string) => RequestHandler {
  return (tabId: string) => (req: AuthenticatedRequest, res, next) => {
    if (!req.user) {
      res.status(401).json({ message: "Unauthenticated" });
      return;
    }

    if (req.user.role === "superuser") {
      next();
      return;
    }

    const deniedTabs = String(req.headers["x-test-deny-tabs"] || "")
      .split(",")
      .map((value) => value.trim())
      .filter(Boolean);

    if (deniedTabs.includes(tabId)) {
      res.status(403).json({ message: `Tab '${tabId}' is disabled for role '${req.user.role}'` });
      return;
    }

    next();
  };
}

export function allowAllTabs(): RequestHandler {
  return (_req, _res, next) => next();
}
